from pathlib import Path
for fn in ['model.py','predict.py','train.py']:
    p=Path(fn)
    print(f'===== {fn} exists={p.exists()} size={p.stat().st_size if p.exists() else None} =====')
    if not p.exists():
        continue
    lines=p.read_text(errors='replace').splitlines()
    for i,line in enumerate(lines[:260],1):
        print(f'{i:04d}: {line[:180]}')
    if len(lines)>260:
        print(f'... {len(lines)-260} more lines ...')
